import 'package:flutter/material.dart';import 'package:provider/provider.dart';import '../../design_system/app_colors.dart';import '../../design_system/app_spacing.dart';import '../../design_system/app_typography.dart';import '../../design_system/ds_card.dart';import '../../design_system/ds_buttons.dart';import '../../design_system/ds_list_item.dart';import '../../providers/insights_provider.dart';import '../../services/mock_data_service.dart';import 'budgets_dashboard_screen.dart';import 'spending_trends_detail_screen.dart';import 'subscriptions_recurring_payments_screen.dart';import 'transaction_list_screen.dart';class InsightsDashboardScreen extends StatelessWidget {  const InsightsDashboardScreen({super.key});  @override  Widget build(BuildContext context) {    return Scaffold(      backgroundColor: AppColors.background,      appBar: AppBar(        title: Text('Insights', style: AppTypography.h2),        centerTitle: false,        actions: [          DsIconButton(icon: Icons.settings_outlined, onPressed: () {            // TODO: Navigate to Settings/Custom Rules            ScaffoldMessenger.of(context).showSnackBar(              const SnackBar(content: Text('Settings/Custom Rules coming soon!')),            );          }),          SizedBox(width: AppSpacing.paddingSmall),        ],      ),      body: Consumer<InsightsProvider>(        builder: (context, insightsProvider, child) {          return RefreshIndicator(            onRefresh: () async {              insightsProvider._loadInsightsData();            },            color: AppColors.primary,            backgroundColor: AppColors.surface,            child: ListView(              padding: AppSpacing.screenPadding,              children: [                _buildCurrentMonthSpendingSummary(context, insightsProvider),                SizedBox(height: AppSpacing.paddingLarge),                _buildBudgetProgressCards(context, insightsProvider),                SizedBox(height: AppSpacing.paddingLarge),                _buildRecurringPaymentsSummary(context, insightsProvider),                SizedBox(height: AppSpacing.paddingLarge),                _buildActionableInsightsCard(context),                SizedBox(height: AppSpacing.paddingLarge),                _buildQuickActions(context),                SizedBox(height: AppSpacing.paddingLarge),                _buildNavigationLinks(context),              ],            ),          );        },      ),    );  }  Widget _buildCurrentMonthSpendingSummary(      BuildContext context, InsightsProvider insightsProvider) {    return DsCard(      child: Column(        crossAxisAlignment: CrossAxisAlignment.start,        children: [          Text(            "Current Month's Spending",            style: AppTypography.body.copyWith(color: AppColors.textSecondary),          ),          SizedBox(height: AppSpacing.paddingSmall),          Text(            MockDataService.formatCurrency(insightsProvider.currentMonthSpending),            style: AppTypography.h1.copyWith(color: AppColors.error),          ),          SizedBox(height: AppSpacing.paddingMedium),          DsPrimaryButton(            text: 'View Spending Trends',            onPressed: () {              Navigator.of(context).push(MaterialPageRoute(                builder: (_) => const SpendingTrendsDetailScreen(),              ));            },          ),        ],      ),    );  }  Widget _buildBudgetProgressCards(      BuildContext context, InsightsProvider insightsProvider) {    return Column(      crossAxisAlignment: CrossAxisAlignment.start,      children: [        Text(          'Budget Progress',          style: AppTypography.h2,        ),        SizedBox(height: AppSpacing.paddingMedium),        if (insightsProvider.budgets.isEmpty)          DsCard(            child: Text(              'No budgets set up yet. Create one to track your spending!',              style: AppTypography.body.copyWith(color: AppColors.textSecondary),            ),          )        else          ...insightsProvider.budgets.map((budget) {            final progress = budget.progress.clamp(0.0, 1.0);            final isOverBudget = budget.isOverBudget;            final textColor = isOverBudget ? AppColors.error : AppColors.textPrimary;            final progressBarColor = isOverBudget ? AppColors.error : AppColors.primary;            return Padding(              padding: const EdgeInsets.only(bottom: AppSpacing.paddingSmall),              child: DsCard(                onTap: () {                  Navigator.of(context).push(MaterialPageRoute(                    builder: (_) => BudgetDetailScreen(budget: budget),                  ));                },                child: Column(                  crossAxisAlignment: CrossAxisAlignment.start,                  children: [                    Text(                      budget.name,                      style: AppTypography.listItemPrimary,                    ),                    SizedBox(height: AppSpacing.paddingSmall / 2),                    Row(                      mainAxisAlignment: MainAxisAlignment.spaceBetween,                      children: [                        Text(                          '${MockDataService.formatCurrency(budget.spentAmount)} spent',                          style: AppTypography.listItemSecondary,                        ),                        Text(                          '${MockDataService.formatCurrency(budget.remainingAmount)} remaining',                          style: AppTypography.listItemSecondary.copyWith(                            color: isOverBudget ? AppColors.error : AppColors.textSecondary,                          ),                        ),                      ],                    ),                    SizedBox(height: AppSpacing.paddingSmall),                    LinearProgressIndicator(                      value: progress,                      backgroundColor: AppColors.surface.withOpacity(0.5),                      valueColor: AlwaysStoppedAnimation<Color>(progressBarColor),                      borderRadius: BorderRadius.circular(AppSpacing.borderRadiusSmall),                      minHeight: 8,                    ),                    SizedBox(height: AppSpacing.paddingSmall),                    if (isOverBudget)                      Text(                        'You are over budget!',                        style: AppTypography.caption.copyWith(color: AppColors.error),                      )                    else if (progress >= budget.alertThreshold)                      Text(                        'You are projected to exceed your ${budget.name} budget.',                        style: AppTypography.caption.copyWith(color: AppColors.secondary),                      ),                  ],                ),              ),            );          }).toList(),        SizedBox(height: AppSpacing.paddingSmall),        DsSecondaryButton(          text: 'Manage Budgets',          onPressed: () {            Navigator.of(context).push(MaterialPageRoute(              builder: (_) => const BudgetsDashboardScreen(),            ));          },        ),      ],    );  }  Widget _buildRecurringPaymentsSummary(      BuildContext context, InsightsProvider insightsProvider) {    return Column(      crossAxisAlignment: CrossAxisAlignment.start,      children: [        Text(          'Recurring Payments',          style: AppTypography.h2,        ),        SizedBox(height: AppSpacing.paddingMedium),        DsCard(          child: Column(            children: [              if (insightsProvider.recurringPayments.isEmpty)                Padding(                  padding: AppSpacing.cardPadding,                  child: Text(                    'No recurring payments detected.',                    style: AppTypography.body.copyWith(color: AppColors.textSecondary),                  ),                )              else                ...insightsProvider.recurringPayments.take(3).map((payment) {                  return DsListItem(                    leading: Container(                      width: AppSpacing.categoryIconSize,                      height: AppSpacing.categoryIconSize,                      decoration: BoxDecoration(                        color: AppColors.primary.withOpacity(0.1),                        borderRadius: BorderRadius.circular(AppSpacing.borderRadiusSmall),                      ),                      child: Icon(Icons.refresh, color: AppColors.primary),                    ),                    title: payment.name,                    subtitle: 'Next: ${MockDataService.formatCurrency(payment.amount)} on ${payment.nextDueDate.day}/${payment.nextDueDate.month}',                    trailingText: MockDataService.formatCurrency(payment.amount),                    trailingTextColor: AppColors.error,                    onTap: () {                      // TODO: Navigate to Recurring Payment Detail                      ScaffoldMessenger.of(context).showSnackBar(                        SnackBar(content: Text('Viewing ${payment.name} details')),                      );                    },                  );                }).toList(),              if (insightsProvider.recurringPayments.length > 3)                Padding(                  padding: const EdgeInsets.only(top: AppSpacing.paddingSmall),                  child: DsSecondaryButton(                    text: 'View All Recurring Payments',                    onPressed: () {                      Navigator.of(context).push(MaterialPageRoute(                        builder: (_) => const SubscriptionsRecurringPaymentsScreen(),                      ));                    },                  ),                ),            ],          ),        ),      ],    );  }  Widget _buildActionableInsightsCard(BuildContext context) {    return DsCard(      child: Column(        crossAxisAlignment: CrossAxisAlignment.start,        children: [          Text(            'Actionable Insights',            style: AppTypography.h2,          ),          SizedBox(height: AppSpacing.paddingMedium),          Text(            "You're projected to exceed your grocery budget by ",            style: AppTypography.body.copyWith(color: AppColors.textSecondary),          ),          Text(            MockDataService.formatCurrency(50.00),            style: AppTypography.body.copyWith(color: AppColors.error),          ),          SizedBox(height: AppSpacing.paddingMedium),          DsSecondaryButton(            text: 'Adjust Budget',            onPressed: () {              // TODO: Navigate to specific budget edit screen              ScaffoldMessenger.of(context).showSnackBar(                const SnackBar(content: Text('Adjusting budget...')),              );            },          ),        ],      ),    );  }  Widget _buildQuickActions(BuildContext context) {    return Column(      crossAxisAlignment: CrossAxisAlignment.start,      children: [        Text(          'Quick Actions',          style: AppTypography.h2,        ),        SizedBox(height: AppSpacing.paddingMedium),        Row(          mainAxisAlignment: MainAxisAlignment.spaceAround,          children: [            _buildQuickActionButton(              context,              icon: Icons.add_circle_outline,              label: 'Add Transaction',              onPressed: () {                // TODO: Implement Add Transaction flow                ScaffoldMessenger.of(context).showSnackBar(                  const SnackBar(content: Text('Add Transaction coming soon!')),                );              },            ),            _buildQuickActionButton(              context,              icon: Icons.camera_alt_outlined,              label: 'Scan Receipt',              onPressed: () {                // TODO: Implement Scan Receipt flow                ScaffoldMessenger.of(context).showSnackBar(                  const SnackBar(content: Text('Scan Receipt coming soon!')),                );              },            ),            _buildQuickActionButton(              context,              icon: Icons.account_balance_wallet_outlined,              label: 'Create Budget',              onPressed: () {                Navigator.of(context).push(MaterialPageRoute(                  builder: (_) => CreateEditBudgetScreen(),                ));              },            ),          ],        ),      ],    );  }  Widget _buildQuickActionButton(      BuildContext context, {    required IconData icon,    required String label,    required VoidCallback onPressed,  }) {    return Column(      children: [        DsIconButton(          icon: icon,          onPressed: onPressed,          size: 60, // Slightly larger for quick actions          backgroundColor: AppColors.surface,        ),        SizedBox(height: AppSpacing.paddingSmall),        Text(label, style: AppTypography.caption.copyWith(color: AppColors.textSecondary)),      ],    );  }  Widget _buildNavigationLinks(BuildContext context) {    return Column(      crossAxisAlignment: CrossAxisAlignment.start,      children: [        Text(          'Explore More',          style: AppTypography.h2,        ),        SizedBox(height: AppSpacing.paddingMedium),        _buildNavLink(          context,          'Spending Trends',          Icons.trending_up,          () => Navigator.of(context).push(MaterialPageRoute(            builder: (_) => const SpendingTrendsDetailScreen(),          )),        ),        _buildNavLink(          context,          'Budgets',          Icons.account_balance_wallet_outlined,          () => Navigator.of(context).push(MaterialPageRoute(            builder: (_) => const BudgetsDashboardScreen(),          )),        ),        _buildNavLink(          context,          'Subscriptions',          Icons.subscriptions_outlined,          () => Navigator.of(context).push(MaterialPageRoute(            builder: (_) => const SubscriptionsRecurringPaymentsScreen(),          )),        ),        _buildNavLink(          context,          'Custom Rules',          Icons.rule_folder_outlined,          () {            // TODO: Navigate to Custom Rules Management            ScaffoldMessenger.of(context).showSnackBar(              const SnackBar(content: Text('Custom Rules Management coming soon!')),            );          },        ),        _buildNavLink(          context,          'Reports',          Icons.bar_chart_outlined,          () {            // TODO: Navigate to Reports & Export            ScaffoldMessenger.of(context).showSnackBar(              const SnackBar(content: Text('Reports & Export coming soon!')),            );          },        ),      ],    );  }  Widget _buildNavLink(      BuildContext context, String title, IconData icon, VoidCallback onTap) {    return Padding(      padding: const EdgeInsets.only(bottom: AppSpacing.paddingSmall),      child: DsCard(        onTap: onTap,        padding: const EdgeInsets.symmetric(          vertical: AppSpacing.paddingMedium,          horizontal: AppSpacing.paddingLarge,        ),        child: Row(          children: [            Icon(icon, color: AppColors.primary, size: AppSpacing.iconSizeMedium),            SizedBox(width: AppSpacing.paddingMedium),            Expanded(              child: Text(                title,                style: AppTypography.body,              ),            ),            Icon(Icons.arrow_forward_ios,                color: AppColors.textSecondary, size: AppSpacing.iconSizeMedium / 1.5),          ],        ),      ),    );  }}